
import React from 'react';
import Container from 'react-bootstrap/Container';
import Row from 'react-bootstrap/Row';
import Col from 'react-bootstrap/Col';

function Hero(props) {

    return(
        <header className="hero">
            <Container fluid={true}>
                <Row className="justify-content-center">
                    <Col md={8} sm={10}>
                        { props.title && <h1 className="display-3">{props.title}</h1> }
                        { props.subTitle && <p className="hero-subtitle text-secondary">{props.subTitle}</p> }
                        { props.text && <p className="hero-cta">{props.text}</p> }
                        { props.title || props.subTitle ? <div className="hero-divider" /> : null }
                    </Col>
                </Row>
            </Container>
        </header>
    );

}


export default Hero;