import React from 'react';

import CardInfo from './CardInfoPages';

const PLACEHOLDER_SRC = '';

function maybeLoad(src) {
  return typeof src === 'string' && src.trim().length > 0 ? src : PLACEHOLDER_SRC;
}

function CardPages(props) {
    const item = props.item || {};

    return(
        <div className="d-inline-block g-cardPages" onClick={(e) => props.click && props.click(item, e)}>
            <img
                className="g-card-imagePages"
                src={maybeLoad(item.imgSrc)}
                alt={item.title || 'portfolio image'}
            />
            <CardInfo title={item.title} subTitle={item.subTitle} link={item.link} />
        </div>
    );

}

export default CardPages;
